#ifndef QiFIELD_H
#define QiFIELD_H

#include <QJsonObject>
#include <QJsonArray>
#include <QJsonDocument>
#include <QMap>
#include <QStringList>

/// Database field
/**
    QiField store the value of a field in database model. The format is QVariant.
    Therefore you may assign a QVariant to QiField direclty, and you may access
    the stored QVariant by using operator-> or get() function.

    @see QiModel
    @see QiForeignKey
 */

template <typename T>
class QiField : public QiBaseField
{
public:
    /// Default constructor
    QiField(){
    }

    /// Return the QMetaType id of the field
    static int type(){
        return qMetaTypeId<T>();
    }

    /// Copy the value from a QVariant object
    inline QVariant operator=(const QVariant &val){
        set(val);
        return val;
    }

    /// Compare with other QiField
    inline bool operator==(const QiField& rhs) const {
        return get() == rhs.get();
    }

    /// Compare with QVariant type
    inline bool operator==(const QVariant &rhs) const {
        return get() == rhs;
    }

    /// Compare with QVariant type
    inline bool operator!=(const QVariant &rhs) const {
        return get() != rhs;
    }

    /// Compare with its template type
    inline bool operator==(const T& t) const {
        return get() == t;
    }

    /// Compare with its template type
    inline bool operator!=(const T& t) const {
        return get() != t;
    }

    /// Compare with string type
    inline bool operator==(const char *string) const {
        return get() == QString(string);
    }

    /// Compare with string type
    inline bool operator!=(const char *string) const {
        return get() != QString(string);
    }

    /// Get the value of the field
    inline QVariant get(bool convert = false) const {
        return QiBaseField::get(convert);
    }

    /// Set the value of the field
    inline bool set(QVariant value) {
        return QiBaseField::set(value);
    }

    /// Cast it to the template type
    inline operator T() const {
        QVariant v = get();
        return v.value<T>();
    }

};

// The built-in structured-field specializations below are defined `inline` in
// the header (not out-of-line in a .cpp) on purpose. get()/set() are virtual,
// and MSVC does not reliably emit an out-of-line explicit specialization of a
// virtual member unless the enclosing class template is instantiated in that
// same translation unit — which it isn't. Defining them inline gives every TU
// (and every compiler) the definition, matching the QI_DECLARE_CONVERTER pattern.

namespace QiFieldDetail {

/// Escape & and " so list items survive being joined with the separator.
inline QString escapeStringListItem(QString value) {
    QString result;
    QMap<char, QString> map;
    map['&'] = "&amp;";
    map['"'] = "&quot;";

    result.reserve(value.size() * 1.1);
    int n = value.size();
    for (int i = 0; i < n; i++) {
        QChar c = value.at(i);
        char l = c.toLatin1();
        if (map.contains(l)) {
            result += map[l];
        } else {
            result += c;
        }
    }
    result.squeeze();
    return result;
}

inline QString unescapeStringListItem(QString value) {
    QMap<QString, char> map;
    map["&amp;"] = '&';
    map["&quot;"] = '"';

    QString result;
    result.reserve(value.size());

    int n = value.size();
    for (int i = 0; i < n; i++) {
        QChar q = value.at(i);

        if (q == '&') {
            bool found = false;
            QMap<QString, char>::const_iterator iter = map.constBegin();
            while (iter != map.end()) {
                QString key = iter.key();
                int len = key.size();

                QStringView ref = QStringView(value).mid(i, len);
                if (ref == QStringView(key)) {
                    q = iter.value();
                    i += len - 1;
                    found = true;
                    break;
                }
                iter++;
            }

            if (!found) {
                qWarning() << QString("Invalid escaped string : %1").arg(value);
            }
        }

        result += q;
    }

    result.squeeze();
    return result;
}

/// Separator for QStringList storage.
inline const char *stringListSeparator() { return " & "; }

} // namespace QiFieldDetail

template <>
inline bool QiField<QStringList>::set(QVariant value) {
    if (value.userType() == QMetaType::QString) {
        QString str = value.toString();
        QStringList list = str.split(QiFieldDetail::stringListSeparator());
        QStringList result;
        foreach (str, list) {
            result << QiFieldDetail::unescapeStringListItem(str);
        }
        value = result;
    }
    return QiBaseField::set(value);
}

template <>
inline QVariant QiField<QStringList>::get(bool convert) const {
    QVariant val = QiBaseField::get(convert);

    if (convert && val.userType() == QMetaType::QStringList) {
        QStringList list = val.toStringList();
        QStringList result;
        QString str;
        foreach (str, list) {
            result << QiFieldDetail::escapeStringListItem(str);
        }
        val = result.join(QiFieldDetail::stringListSeparator());
    }

    return val;
}

// Structured JSON fields: hold a nested QJsonObject / QJsonArray in memory,
// serialize to a JSON string only when persisted (convert = true).
template <>
inline bool QiField<QJsonObject>::set(QVariant value) {
    if (value.userType() == QMetaType::QString)
        value = QJsonDocument::fromJson(value.toString().toUtf8()).object();
    return QiBaseField::set(value);
}

template <>
inline QVariant QiField<QJsonObject>::get(bool convert) const {
    QVariant val = QiBaseField::get(convert);
    if (convert && val.userType() == QMetaType::QJsonObject)
        return QString::fromUtf8(QJsonDocument(val.toJsonObject()).toJson(QJsonDocument::Compact));
    return val;
}

template <>
inline bool QiField<QJsonArray>::set(QVariant value) {
    if (value.userType() == QMetaType::QString)
        value = QJsonDocument::fromJson(value.toString().toUtf8()).array();
    return QiBaseField::set(value);
}

template <>
inline QVariant QiField<QJsonArray>::get(bool convert) const {
    QVariant val = QiBaseField::get(convert);
    if (convert && val.userType() == QMetaType::QJsonArray)
        return QString::fromUtf8(QJsonDocument(val.toJsonArray()).toJson(QJsonDocument::Compact));
    return val;
}

/// Primary key field

class QiPrimaryKey : public QiField<int> {
public:
    QiPrimaryKey();
    static QiClause clause();

    inline QVariant operator=(const QVariant &val){
        set(val);
        return val;
    }
};

/// Store an arbitrary C++ value type in a column via a pair of conversion functions.
/**
  Teaches QiField how to persist a custom type `TYPE`. Provide two free/static
  functions (by name — not inline lambdas, so the macro stays comma-safe):

    - `TO_STORAGE_FN(const TYPE&) -> QVariant`   a value SQLite can store
                                                 (int / double / QString / ...)
    - `FROM_STORAGE_FN(const QVariant&) -> TYPE` rebuild the value when loading

  `TYPE` must be registered with `Q_DECLARE_METATYPE(TYPE)`, and the column's SQL
  type should be set with `QI_FIELD_AS(field, "TEXT")` (or INTEGER/REAL/…).

\code
    struct GeoPoint { double lat, lng; };
    Q_DECLARE_METATYPE(GeoPoint)

    static QVariant geoToStorage(const GeoPoint &p) {
        return QStringLiteral("%1,%2").arg(p.lat).arg(p.lng);
    }
    static GeoPoint geoFromStorage(const QVariant &v) {
        const QStringList s = v.toString().split(',');
        return GeoPoint{ s.value(0).toDouble(), s.value(1).toDouble() };
    }
    QI_DECLARE_CONVERTER(GeoPoint, geoToStorage, geoFromStorage)

    // in the model:  QI_FIELD_AS(location, "TEXT")
\endcode

  Place the macro (and the two functions) before any model that uses
  `QiField<TYPE>`.
 */
#define QI_DECLARE_CONVERTER(TYPE, TO_STORAGE_FN, FROM_STORAGE_FN)          \
    template <> inline bool QiField<TYPE>::set(QVariant value) {            \
        if (value.isValid() && !value.isNull()                             \
                && value.userType() != qMetaTypeId<TYPE>())                \
            value = QVariant::fromValue<TYPE>( FROM_STORAGE_FN(value) );    \
        return QiBaseField::set(value);                                     \
    }                                                                       \
    template <> inline QVariant QiField<TYPE>::get(bool convert) const {    \
        QVariant _v = QiBaseField::get(convert);                           \
        if (convert && _v.userType() == qMetaTypeId<TYPE>())               \
            return QVariant( TO_STORAGE_FN( _v.value<TYPE>() ) );          \
        return _v;                                                          \
    }

#endif // QiFIELD_H

// ---- src/qifieldref.h --------------------------------------------
#ifndef QiFIELDREF_H
#define QiFIELDREF_H

#include <cstddef>

/// A type-safe, refactor-proof reference to a model field, as a QiWhere.
/**
  Instead of hardcoding a column-name string, pass a pointer-to-member. The
  compiler checks the member exists, and renaming the field is caught at compile
  time instead of silently breaking a query at runtime.

\code
    User user;
    user.load( qiField(&User::userId) == "anonymous" );          // no "userId" string

    auto top = User::objects()
                 .filter( qiField(&User::karma) > 100 )
                 .orderBy("karma desc")
                 .all();
\endcode

  Works for any field you declare on the model. For the built-in primary key,
  use `QiWhere("id")` (or the explicit form `qiField<User>(&User::id)`), because
  `id` is inherited from QiModel.

  @param member A pointer to a QiField member of model T (e.g. `&User::userId`).
  @return A QiWhere field for use with the comparison operators, or a null
          QiWhere if the member is not a registered field.
 */
template <typename T, typename M>
inline QiWhere qiField(M T::* member) {
    T probe;
    const size_t offset = reinterpret_cast<size_t>(&(probe.*member))
                        - reinterpret_cast<size_t>(&probe);

    QiModelMetaInfo *info = qiMetaInfo<T>();
    const int n = info->size();
    for (int i = 0; i < n; i++) {
        if (static_cast<size_t>(info->at(i)->offset) == offset)
            return QiWhere(info->at(i)->name);
    }
    return QiWhere();
}

#endif // QiFIELDREF_H

// ---- src/qijoin.h ------------------------------------------------
#ifndef QiJOIN_H
#define QiJOIN_H

#include <QString>
#include <QtGlobal>

/// A single JOIN clause in a query
/**
  QiBaseJoin is the base class of QiJoin. It stores the joined table (through
  its QiModelMetaInfo), the join type and the ON condition.

  Normally you do not construct QiBaseJoin directly. Use the typed QiJoin\<T\>
  and pass it to QiSharedQuery::join().

\code
    // SELECT ... FROM user INNER JOIN friendship ON friendship.a = user.id
    QiList<User> list = User::objects()
            .join( QiJoin<FriendShip>( QiWhere("friendship.a") == QiWhere("user.id") ) )
            .filter( QiWhere("friendship.b") == tester2.id )
            .all();
\endcode
 */
class QiBaseJoin {
public:
    /// The type of the join
    enum Type {
        Inner = 0,  ///< INNER JOIN
        Left,       ///< LEFT OUTER JOIN
        Right,      ///< RIGHT OUTER JOIN (requires SQLite >= 3.39)
        Full,       ///< FULL OUTER JOIN (requires SQLite >= 3.39)
        Cross       ///< CROSS JOIN (no ON condition)
    };

    /// Construct a null join
    QiBaseJoin() : m_metaInfo(0) , m_type(Inner) {
    }

    /// Construct a join
    /**
      @param metaInfo The meta info of the joined model
      @param on The ON condition. Leave it null for a CROSS JOIN.
      @param type The type of join
     */
    QiBaseJoin(QiModelMetaInfo *metaInfo, QiWhere on , Type type = Inner)
        : m_metaInfo(metaInfo) , m_on(on) , m_type(type) {
    }

    /// Construct a join to a raw table name (not a registered model)
    /**
      Useful for joining tables Qivot does not model, such as an FTS5 virtual
      table. Only an explicit ON condition is supported (no auto foreign-key
      derivation).
     */
    QiBaseJoin(QString table, QiWhere on , Type type = Inner)
        : m_metaInfo(0) , m_table(table) , m_on(on) , m_type(type) {
    }

    /// The meta info of the joined model (null for a raw-table join)
    QiModelMetaInfo *metaInfo() const {
        return m_metaInfo;
    }

    /// The table name of the joined table
    QString table() const {
        if (!m_table.isEmpty())
            return m_table;
        return m_metaInfo ? m_metaInfo->name() : QString();
    }

    /// The ON condition of the join, as supplied by the user (may be null)
    QiWhere on() const {
        return m_on;
    }

    /// The effective ON condition of the join given the primary model
    /**
      If an explicit ON condition was supplied, it is returned unchanged.
      Otherwise (and unless this is a CROSS join) the ON condition is derived
      from a QiForeignKey declared between the primary model and the joined
      model, in either direction:

        - joined model has a foreign key referencing the primary table
              => "<joined>.<fk> = <primary>.id"
        - primary model has a foreign key referencing the joined table
              => "<primary>.<fk> = <joined>.id"

      @param primary The meta info of the query's primary model.
      @return The resolved ON condition, or a null QiWhere if none applies
              (CROSS join, or no foreign key relationship could be found).
     */
    QiWhere resolvedOn(QiModelMetaInfo *primary) const {
        QiWhere explicitOn = m_on;
        if (!explicitOn.isNull())
            return explicitOn;

        if (m_type == Cross || primary == 0 || m_metaInfo == 0)
            return QiWhere();

        QString pTable = primary->name();
        QString jTable = m_metaInfo->name();

        QList<QiWhere> candidates;

        // Case 1: the joined model references the primary model.
        QList<QiModelMetaInfoField> jfks = m_metaInfo->foreignKeyList();
        for (int i = 0 ; i < jfks.size() ; i++) {
            if (foreignKeyTarget(jfks.at(i)) == primary) {
                candidates << ( QiWhere(jTable + "." + jfks.at(i).name)
                                == QiWhere(pTable + ".id") );
            }
        }

        // Case 2: the primary model references the joined model.
        QList<QiModelMetaInfoField> pfks = primary->foreignKeyList();
        for (int i = 0 ; i < pfks.size() ; i++) {
            if (foreignKeyTarget(pfks.at(i)) == m_metaInfo) {
                candidates << ( QiWhere(pTable + "." + pfks.at(i).name)
                                == QiWhere(jTable + ".id") );
            }
        }

        if (candidates.isEmpty()) {
            qWarning("QiJoin: no foreign key relationship found between \"%s\" and \"%s\". "
                     "Provide an explicit ON condition.",
                     qPrintable(pTable) , qPrintable(jTable));
            return QiWhere();
        }

        if (candidates.size() > 1) {
            qWarning("QiJoin: ambiguous foreign key relationship between \"%s\" and \"%s\" "
                     "(%d candidates). Using the first; provide an explicit ON condition "
                     "to disambiguate.",
                     qPrintable(pTable) , qPrintable(jTable) , candidates.size());
        }

        return candidates.first();
    }

    /// The type of the join
    Type type() const {
        return m_type;
    }

    /// The SQL keyword(s) for the join type (e.g. "INNER JOIN")
    QString keyword() const {
        switch (m_type) {
        case Left:  return QStringLiteral("LEFT OUTER JOIN");
        case Right: return QStringLiteral("RIGHT OUTER JOIN");
        case Full:  return QStringLiteral("FULL OUTER JOIN");
        case Cross: return QStringLiteral("CROSS JOIN");
        case Inner:
        default:    return QStringLiteral("INNER JOIN");
        }
    }

private:
    /// Resolve the target model referenced by a foreign key field
    static QiModelMetaInfo *foreignKeyTarget(QiModelMetaInfoField field) {
        QVariant v = field.clause.flag(QiClause::FOREIGN_KEY);
        return (QiModelMetaInfo *) v.value<void *>();
    }

    QiModelMetaInfo *m_metaInfo;
    QString m_table;
    QiWhere m_on;
    Type m_type;
};

/// A typed JOIN clause on model T
/**
  QiJoin\<T\> is a convenience wrapper that resolves the QiModelMetaInfo of the
  model T automatically.

\code
    // INNER JOIN (default)
    query.join( QiJoin<FriendShip>( QiWhere("friendship.a") == QiWhere("user.id") ) );

    // LEFT OUTER JOIN
    query.join( QiJoin<FriendShip>( QiWhere("friendship.a") == QiWhere("user.id"),
                                    QiBaseJoin::Left ) );

    // CROSS JOIN (no ON condition)
    query.join( QiJoin<FriendShip>( QiWhere() , QiBaseJoin::Cross ) );
\endcode
 */
template <typename T>
class QiJoin : public QiBaseJoin {
public:
    /// Construct a join to the table of model T
    /**
      @param on   The ON condition of the join. Leave null for a CROSS JOIN.
      @param type The type of join (defaults to INNER JOIN)
     */
    QiJoin(QiWhere on = QiWhere() , Type type = Inner)
        : QiBaseJoin( qiMetaInfo<T>() , on , type ) {
    }
};

#endif // QiJOIN_H

// ---- src/qisharedquery.h -----------------------------------------
#ifndef QiSHAREDQUERY_H
#define QiSHAREDQUERY_H

#include <QSharedDataPointer>
#include <QExplicitlySharedDataPointer>

class QiSharedQueryPriv;
class QiConnection;
class QiWhere;

/// QiSharedQuery is the base class of QiQuery that support implicitly data sharing
/**
  QiSharedQuery is the base class of QiQuery that hold all the information for a query.
  It is a implicitly shared class which is designed for query data exchange between
  different objects.

  Although most of the function return QiSharedQuery instead of QiQuery , user should
  always use QiQuery.  They are exchangable, that means QiSharedQuery can be converted
  to QiQuery, and vice visa.

  @remarks It is a implicitly shared class
 */

class QiSharedQuery
{
public:

    /// Construct a QiSharedQuery object and use the default database connection
    QiSharedQuery();

    /// Construct a QiSharedQuery object and set the database connection
    QiSharedQuery(QiConnection connection);

    /// Copy constructor
    QiSharedQuery(const QiSharedQuery &);

    /// Assignment operator overloading
    QiSharedQuery &operator=(const QiSharedQuery &);

    /// Default destructor
    ~QiSharedQuery();

    /// Set the connection
    void setConnection(QiConnection connection);

    /// Construct a new query object with only the fields assigned in result
    /**
        By default, QiSharedQuery retrieve all the field of the model.
        Call this function if you only interest for specific fields.

        @remarks If you don't specific the "id" field. It will not load the field. If you save the model , it will insert a new entity to the database.
     */
    QiSharedQuery select(QStringList fields);

    /// Construct a new query object with only a single field in result
    /**
        By default, QiSharedQuery retrieve all the field of the model.
        Call this function if you only interest for a single field

        @remarks If the field is not the "id" field, and you call the save() method on the model. It will insert a new entity to the database
     */
    QiSharedQuery select(QString field);

    /// Construct a new query object with assigned filter
    QiSharedQuery filter(QiWhere where);

    /// Construct a new query object with an additional JOIN clause
    /**
      The joined table becomes available to the filter() and ON conditions.
      You may qualify column names with the table name (e.g. "user.id") to
      disambiguate between the joined tables. The query still returns records
      of the primary model.

      @param join The join clause, normally a typed QiJoin\<T\> instance.

      Example:
\code
    // SELECT ... FROM user INNER JOIN friendship ON friendship.a = user.id
    //            WHERE friendship.b = <tester2.id>
    QiList<User> friends = User::objects()
            .join( QiJoin<FriendShip>( QiWhere("friendship.a") == QiWhere("user.id") ) )
            .filter( QiWhere("friendship.b") == tester2.id )
            .all();
\endcode

      @see QiJoin
     */
    QiSharedQuery join(const QiBaseJoin &join);

    /// Construct a new query object with an automatic JOIN to model T
    /**
      The ON condition is derived from a QiForeignKey declared between the
      primary model and T (in either direction). It is a shortcut for
      join( QiJoin\<T\>() ).

\code
    // Config declares QiForeignKey<User> uid , so the ON condition
    // "user.id = config.uid" is derived automatically.
    QiList<Config> list = Config::objects()
            .join<User>()
            .filter( QiWhere("user.userId") == "tester1" )
            .all();
\endcode

      @remarks If the relationship is ambiguous (e.g. two foreign keys to the
      same table), pass an explicit ON condition with QiJoin\<T\> instead.
     */
    template <typename T>
    QiSharedQuery join() {
        return join( QiJoin<T>() );
    }

    /// Construct a new query object that removes duplicate rows (SELECT DISTINCT)
    /**
      This is most useful together with join(), where a single primary record
      may be produced several times (once per matching row in the joined table).

      @param enabled Pass false to turn DISTINCT off again.
     */
    QiSharedQuery distinct(bool enabled = true);

    /// Construct a new query object with limitation no. of result
    QiSharedQuery limit(int val);

    /// Construct a new query object that skips the first @p val rows (for pagination)
    QiSharedQuery offset(int val);

    /// Construct a new query object grouped by the given column(s) (GROUP BY)
    QiSharedQuery groupBy(QStringList terms);

    /// Construct a new query object grouped by a single column (GROUP BY)
    QiSharedQuery groupBy(QString term);

    /// Construct a new query object with a HAVING filter on grouped results
    QiSharedQuery having(QiWhere where);

    /// Construct a new query object with required sorting order
    /**
      @param terms The ordering terms

      The ordering terms is basically equal to the field name.
      You may add the clause ASC / DESC next to the field name,
      then it will be sorted by asc / desc ordering.

      Example:
\code
    QiQuery<HealthCheck> query;

    QiList<HealthCheck> result;

    result = query.orderBy("height").all();
    result = query.orderBy("height asc").all();
    result = query.orderBy("height desc").all();

\endcode

     */
    QiSharedQuery orderBy(QStringList terms);

    /// Construct a new query object with required sorting order
    /**
      It is a overloaded function
     */
    QiSharedQuery orderBy(QString term);

    /// Execute the query
    [[nodiscard]] bool exec();

    /// Retrieves the next record in the result, if available, and positions the query on the retrieved record.
    bool next();

    /// Retrieves the first field of the current record. It is useful for query like count() / max() , ... that will only have a single field result
    QVariant value();

    /// Retrieves the field at @p index of the current record
    /**
      Useful for reading grouped/aggregate results, e.g. a
      `select({"author", "count(*)"})` + `groupBy("author")` query where each
      row has the group column at index 0 and the aggregate at index 1.
     */
    QVariant value(int index);

    /// Execute the query and count no. of record retrieved
    int count();

    /// Execute the query and call specific function on the result
    /**
      @param func The function name (e.g sum , avg , ...)
      @param fields A list of fields that could be passed to the function
     */
    QVariant call(QString func , QStringList fields = QStringList());

    /// Execute the query and call specific function on the result
    /**
      @param func The function name (e.g sum , avg , ...)
      @param field The field that should be passed to the function
     */
    QVariant call(QString func , QString field);

    /// Delete all the records fullfill the filter rules
    /**
      @return TRUE if the operation is successfully run , otherwise it is false.
     */
    [[nodiscard]] bool remove();

    /// Update all records matching the filter in a single UPDATE statement
    /**
      Sets the given columns on every row that matches the query's filter,
      without loading them:

\code
    int changed = User::objects()
                      .filter( User::col().karma < 0 )
                      .update({ {"karma", 0}, {"name", "reset"} });
\endcode

      @param values Column name -> new value.
      @return The number of rows updated, or -1 on error.
     */
    int update(const QVariantMap &values);

    /// Execute the query and return all the record retrieved
    QiSharedList all();

    /// Returns the QSqlQuery object being used
    QSqlQuery lastQuery();

    /// Reset the query to initial status , but keep the connection and associated object unchanged.
    void reset();

protected:

    /// Set the associated data model
    void setMetaInfo(QiModelMetaInfo *info);

    /* The design of QiSharedQuery do not allow user to pass QiModel to any argument.
       Prevent invalid pointer type passed
     */

    /// Save the current record to a QiModel
    bool recordTo(QiAbstractModel *model);

    /// Get a single record that first match with the filter (limit(1) will be set)
    /**
      @param model The record will be saved to the object
      @return TRUE if success , the result will be saved to the model argument. Otherwise it is false.
     */
    bool get(QiAbstractModel* model);


private:
    QSharedDataPointer<QiSharedQueryPriv> data;

    friend class QiQueryRules;
};

#endif // QiSHAREDQUERY_H

// ---- src/qilist.h ------------------------------------------------
#ifndef QiLIST_H
#define QiLIST_H

#include <QSharedDataPointer>
#include <QExplicitlySharedDataPointer>

/// Storage of a list of model item instance
/**

  @remarks It is an explicity shared class
 */

template <class T>
class QiList : public QiSharedList
{
public:

    /// Construct an empty QiList instance
    QiList() : QiSharedList() {
        setMetaInfo(qiMetaInfo<T>());
    }

    /// Construct a QiList which is the reference to other QiList instance
    QiList(const QiList &rhs) : QiSharedList(rhs) {
    }

    /// Construct a QiList which is a refernece to a QiSharedList
    QiList(const QiSharedList& rhs ) : QiSharedList(rhs) {
    }

    /// Make a reference to other QiList
    /** It will drop the reference of current data and refer to other QiList
     */
    QiList &operator=(const QiList &rhs){
        QiSharedList::operator=( rhs);
        return *this;
    }

    /// Returns the item at index position i in the list. i must be a valid index position in the list (i.e., 0 <= i < size()).
    T* at(int i) const {
        QiAbstractModel* m = QiSharedList::at(i);
        if (m->metaInfo() != qiMetaInfo<T>() ) {
            qWarning() << QString("QiList::at() - Can not convert %1 to %2")
                          .arg(m->metaInfo()->className()).arg(qiMetaInfo<T>()->className());
            m = 0;
        }
        return (T*) m;
    }

    /// Append a model to the list
    /**
      It is a overloaded function for append().
     */
    QiList& operator<<(const T& model){
        if (!append(model)){
            qWarning() << "QiList::operator<<(model) - Failed to append";
        }
        return *this;
    }


    /// Append a model to the list.
    /**
      @param model The input model. A copy of instance of the model will be stored to the list.
     */
    bool append(const T& model) {
        T* t = new T(model);
        bool res = QiSharedList::append(t);
        if (!res) {
            delete t;
        }
        return res;
    }

    /// Append a model to the list.
    /**
      @param model The input model. Ownership will be taken.
     */

    bool append(T* model) {
        return QiSharedList::append(model);
    }

    /// Cast it to QiSharedList
    operator QiSharedList() {
        QiSharedList res (*this);
        return res;
    }

};

template <class T>
inline QDebug operator<< (QDebug d, const QiList<T>& rhs ){
    QStringList record;
    int n = rhs.size();
    QiModelMetaInfo *metaInfo;
    for (int i = 0 ; i < n;i++) {
        QiAbstractModel *model = rhs.at(i);
        metaInfo = model->metaInfo();
        QStringList fields = metaInfo->fieldNameList();
        QStringList col;
        foreach (QString field,fields){
            QVariant value = metaInfo->value(model,field);
            if (value.isNull())
                continue;
            col << QString("%1=%2").arg(field).arg(value.toString());
        }

        QString res = QString("(%2)")
                      .arg(col.join(","));
        record << res;
    }

    metaInfo = qiMetaInfo<T>();

    d.nospace() << QString("%1[%2]")
                    .arg(metaInfo->className())
                    .arg(record.join(","));

    return d.space();
}


#endif // QiLIST_H

// ---- src/qiquery.h -----------------------------------------------
#ifndef QiQUERY_H
#define QiQUERY_H

#include <QSqlQuery>
#include <QSqlRecord>
#include <QVariantList>

///  QiQuery is a template class for performing database queries and record deletion on specific model
/**
  @remarks It is a implicitly shared class
 */
template <typename T>
class QiQuery : public QiSharedQuery{
public:

    /// Construct q QiQuery and use default connection
    QiQuery();

    /// Construct a QiQuery object and set the database connection
    QiQuery(QiConnection connection)  : QiSharedQuery(connection) {
        setMetaInfo(qiMetaInfo<T>());
    }

    /// Copy and convert from a QiSharedQuery instance
    QiQuery(const QiSharedQuery &rhs) : QiSharedQuery(rhs) {
        setMetaInfo(qiMetaInfo<T>());
    }

    /// Copy from other QiQuery instance
    /** Declared explicitly (matching operator= below) so the implicit copy ctor
        isn't used — that pairing triggers -Wdeprecated-copy-with-user-provided-copy. */
    QiQuery(const QiQuery &rhs) : QiSharedQuery(rhs) {
        setMetaInfo(qiMetaInfo<T>());
    }

    /// Copy from other QiQuery instance
    QiQuery& operator=(const QiQuery &rhs ) {
        QiSharedQuery::operator =(rhs);
        setMetaInfo(qiMetaInfo<T>());
        return *this;
    }

    /// Copy and convert from a QiSharedQuery instance
    QiQuery& operator=(const QiSharedQuery &rhs ) {
        QiSharedQuery::operator =(rhs);
        setMetaInfo(qiMetaInfo<T>());
        return *this;
    }

    /* Typed fluent overloads.

       These shadow the QiSharedQuery methods so the whole chain stays a
       QiQuery<T>, and all() returns a QiList<T>. That keeps element access
       typed (list.at(i) -> T*) and lets callers write `auto`:

           auto users = QiQuery<User>().filter(QiWhere("karma") > 0).all();
     */

    /// Construct a new query object with only the given fields in the result
    QiQuery<T> select(QStringList fields) { return QiSharedQuery::select(fields); }

    /// Construct a new query object with only a single field in the result
    QiQuery<T> select(QString field) { return QiSharedQuery::select(field); }

    /// Construct a new query object with an assigned filter
    QiQuery<T> filter(QiWhere where) { return QiSharedQuery::filter(where); }

    /// Construct a new query object with an additional JOIN clause
    QiQuery<T> join(const QiBaseJoin &join) { return QiSharedQuery::join(join); }

    /// Construct a new query object with an automatic JOIN to model M
    template <typename M>
    QiQuery<T> join() { return QiSharedQuery::join<M>(); }

    /// Construct a new query object that removes duplicate rows (SELECT DISTINCT)
    QiQuery<T> distinct(bool enabled = true) { return QiSharedQuery::distinct(enabled); }

    /// Construct a new query object with a limit on the number of results
    QiQuery<T> limit(int val) { return QiSharedQuery::limit(val); }

    /// Construct a new query object that skips the first @p val rows (pagination)
    QiQuery<T> offset(int val) { return QiSharedQuery::offset(val); }

    /// Construct a new query object grouped by the given column(s)
    QiQuery<T> groupBy(QStringList terms) { return QiSharedQuery::groupBy(terms); }

    /// Construct a new query object grouped by a single column
    QiQuery<T> groupBy(QString term) { return QiSharedQuery::groupBy(term); }

    /// Construct a new query object with a HAVING filter on grouped results
    QiQuery<T> having(QiWhere where) { return QiSharedQuery::having(where); }

    /// Construct a new query object with the required sorting order
    QiQuery<T> orderBy(QStringList terms) { return QiSharedQuery::orderBy(terms); }

    /// Construct a new query object with the required sorting order
    QiQuery<T> orderBy(QString term) { return QiSharedQuery::orderBy(term); }

    /// Execute the query and return all the records as a typed QiList<T>
    QiList<T> all() { return QiList<T>( QiSharedQuery::all() ); }

    /// Construct a full-text search query against an FTS5 index
    /**
      Joins the model to its FTS5 index on the row id, filters by the MATCH
      query, and orders by relevance (rank). The index must have been created
      with QiConnection::createFtsIndex.

\code
    QiList<Article> hits = QiQuery<Article>()
            .search("article_fts", "sqlite AND orm")
            .limit(20)
            .all();
\endcode

      @param ftsTable The FTS5 virtual table name (as given to QiFtsIndex).
      @param query    An FTS5 MATCH query string.
     */
    QiQuery<T> search(const QString &ftsTable, const QString &query) {
        QString base = qiMetaInfo<T>()->name();
        QiBaseJoin join( ftsTable ,
                         QiWhere(base + ".id") == QiWhere(ftsTable + ".rowid") );
        return QiSharedQuery::join(join)
                .filter( QiWhere(ftsTable).expr("match", query) )
                .orderBy( ftsTable + ".rank" );
    }

    /// Save the next record to QiModel
    bool recordTo(T &model) {
        return QiSharedQuery::recordTo(&model);
    }

    /// Read the next record
    T record() {
        T t;
        QiSharedQuery::recordTo(&t);
        return t;
    }

};

template <typename T>
QiQuery<T>::QiQuery() : QiSharedQuery() {
    setMetaInfo(qiMetaInfo<T>());
}

/// Run arbitrary SQL and map each row into a typed `QiList<T>`.
/**
  The typed escape hatch for anything the query builder doesn't express — a
  correlated subquery, a `WITH` CTE, a window function, `UNION`, etc. Write a
  `SELECT` whose result columns are named like the model's fields; each row is
  materialized into a `T`. Positional `?` placeholders bind from `binds`.

\code
    // running total via a window function, still returns typed Order objects:
    auto rows = qiRawQuery<Order>(
        "SELECT *, sum(total) OVER (ORDER BY id) AS runningTotal "
        "FROM orders WHERE total > ?", { 1000 });

    // IN (subquery):
    auto vip = qiRawQuery<User>(
        "SELECT * FROM user WHERE id IN (SELECT userId FROM orders GROUP BY userId "
        "HAVING sum(total) > ?)", { 10000 });
\endcode

  Columns that don't match a field are ignored; extra computed columns (like
  `runningTotal` above) are available on the row via the query but not stored on
  the model unless the model declares a matching field.
 */
template <typename T>
inline QiList<T> qiRawQuery(const QString &sql,
                            const QVariantList &binds = QVariantList(),
                            QiConnection connection = QiConnection::defaultConnection()) {
    QiList<T> result;
    QiModelMetaInfo *info = qiMetaInfo<T>();

    QSqlQuery q = connection.query();
    q.prepare(sql);
    for (const QVariant &b : binds)
        q.addBindValue(b);

    if (q.exec()) {
        const QStringList fields = info->fieldNameList();
        while (q.next()) {
            QiAbstractModel *model = info->create();
            const QSqlRecord rec = q.record();
            for (int i = 0; i < rec.count(); i++) {
                const QString col = rec.fieldName(i);
                if (fields.contains(col))
                    info->setValue(model, col, rec.value(i));
            }
            result.append(static_cast<T *>(model));
        }
    }
    connection.setLastQuery(q);
    return result;
}

#endif // QiQUERY_H

// ---- src/qiforeignkey.h ------------------------------------------
#ifndef QiFOREIGNKEY_H
#define QiFOREIGNKEY_H


/// Foreign key field
/** QiForeignKey is a special kind of QiField which can declare
  a foreign key in SQL scheme.

  The foreign key constraints in SQL are used to enforce "exists"
  relationships between tables. It is a link to other record in same
  or other database table.

  Consider the following data model:

\code
class User : public QiModel
{
    QI_MODEL
public:
    QiField<QString> userId;
    QiField<QString> name;

    QiField<QString> passwd;
}
\endcode

  It is a data model to store user information. Each user may link up other
  with a "friendship" relation:

\code
/// A table to store the friendship status between two user
class FriendShip : public QiModel {
    QI_MODEL
public:

    /// Declara two foreign key to table User
    QiForeignKey<User> a;
    QiForeignKey<User> b;

    QiField<QDateTime> creationDate;

};
\endcode

In this example , a and b is a foreign key to user table. The
field store a integer which is the primary key of the user.

<b> Auto loading </b>

Moreover, QiForeignKey support an auto loading mechanism.
You may access the record "linked" by the QiForeignKey
through its extended interface.

By default, QiForeignKey only store the foreign key value.
Whatever the user request to access the "linked" record
field, it will be loaded automatically.

\code
   FriendShip friendship;
   friendship.load(QiWhere("id") == 1 );

   qDebug() << friendship.a.isLoaded(); // It is false. The foreign key only contains the primary key
   qDebug() << friendship.a->userId; // It will retrieve the user information "linked" by the field "a"
   qDebug() << friendship.a.isLoaded(); // It is true. The foreign key has loaded the content from database
\endcode

<b>Assigment operator</b>

To link with other record, it is just need to use the "=" operator
\code
    User user;
    user.load(QiWhere("id") == 1 );

    friendship.b = user; // friendship.b will store the primary key of "user"
\endcode

 */
template <typename T, int OnDelete = QiFkNoAction>
class QiForeignKey : public QiField<int> {
public:
    /// Construct a foreign key field
    QiForeignKey() : model(0){
    }

    /// Destruct the foreign key field
    ~QiForeignKey() {
        if (model)
            delete model;
    }

    /// Copy from other QiForeignKey object.
    /** It will copy the contained model from other
      QiForeignKey object. The original model
      will destroyed.
     */
    QiForeignKey& operator=(T& rhs) {
        QiModelMetaInfo *info = qiMetaInfo<T>();
        QString pk = info->primaryKeyName();
        if (pk.isEmpty() || pk == QLatin1String("id"))
            set(rhs.id());                       // integer id target (common case)
        else
            set(info->value(&rhs, pk));          // custom string / other primary key
        if (model){
            delete model;
            model = 0;
        }
        model = new T(rhs);

        return *this;
    }

    /// Set the primary key of the "linked" model
    QiForeignKey& operator= (QVariant val) {
        set(val);

        return *this;
    }

    /// Access the data field of the "linked" model
    T* operator->() {
        if (!model)
            model = new T();
        if ( !get().isNull() &&  !isLoaded()  ) {
            load();
        }
        return model;
    }

    /// Return an instance of the "linked" model
    T& operator() () {
        if (!model)
            model = new T();
        if ( !get().isNull() &&  !isLoaded() ) {
            load();
        }
        return *model;
    }

    static QiClause clause() {
        QVariant v = QVariant::fromValue( (void*) qiMetaInfo<T>());
        QiClause c(QiClause::FOREIGN_KEY , v );
        if (OnDelete != QiFkNoAction)
            c = c | QiClause(QiClause::FK_ON_DELETE, OnDelete);
        return c;
    }

    /// TRUE if the model is already loaded.
    inline bool isLoaded() {
        if (!model)
            return false;
        QiModelMetaInfo *info = qiMetaInfo<T>();
        QString pk = info->primaryKeyName();
        QVariant modelKey = (pk.isEmpty() || pk == QLatin1String("id"))
                            ? model->id() : info->value(model, pk);
        return !get().isNull() && !modelKey.isNull() && get() == modelKey;
    }

private:
    bool load();
    T *model;

};

template<typename T, int OnDelete>
bool QiForeignKey<T, OnDelete>::load() {
    bool res = false;
    QiModelMetaInfo *info = qiMetaInfo<T>();
    QString pk = info->primaryKeyName();
    if (pk.isEmpty())
        pk = QStringLiteral("id");
    QiQuery<T> query = QiQuery<T>().filter(QiWhere(pk, "=", get()) ).limit(1);
    if ( query.exec() ){
        if (query.next() ) {
            query.recordTo(*model);
            res = true;
        }
    }

    return res;
}


#endif // QiFOREIGNKEY_H

// ---- src/qimodel.h -----------------------------------------------
#ifndef QiMODEL_H
#define QiMODEL_H

/** @file qimodel.h
    @brief Header file for QiModel

 */

#include <QObject>
#include <QVariant>
#include <QStringList>

/// Database model class
/** QiModel is the core of DQuest that provide an ORM interface to sql database table.
  To declare your database model, you should:

  <ul>
  <li> Create a class that inherits QiModel </li>
  <li> Added a QI_MODEL macro to the class declaration</li>
  <li> Design your database field by using QiField template type</li>
  <li> Register your model with QI_DECLARE_MODEL macro function. </li>
  </ul>

  QiModel can only access a single record in a time. If you need to query multiple
  record , you should use QiQuery. (You may call YourModel::objects() to obtain
  a QiQuery for current model and connection. )

  QiModel itself do not store used query and error message occur. You should
  call QiConnection.lastQuery to obtain the last query object (QSqlQuery).
  It contains the sql being executed and error found.

  @see QI_MODEL
  @see QI_DECLARE_MODEL
  @see QiQuery
  @see QiList
 */

class QiModel : public QiAbstractModel {

public:
    /// QiModel default constructor
    /** The default constructor will set the connection object to be the
      Default connection. So you should use this constructor for single
      database application

     */
    explicit QiModel();

    /// Construct a QiModel object and set the database connection
    explicit QiModel(QiConnection connection);

    virtual ~QiModel();

    /// The primary key. It is default field for every model
    QiPrimaryKey id;

    /// The table name
    virtual QString tableName() const ;

    /// The table name
    static QString TableName();

    enum { QiModelDefined = 0 };

    /// Change the connection
    void setConnection(QiConnection connection);

    /// Get the current connection
    QiConnection connection();

    /// Save the record to database
    /**
      @param forceInsert TRUE if the data should be inserted to the database as a new record regardless of the original id. The id field will be updated after operation.
      @param forceAllField TRUE if all the field should be saved no matter it is null or not. If false, then null field will be skipped.

      If the id is not set , the record will be inserted to the database , then id field will be updated automatically.
      The successive call will update the record instead of insert unless forceInsert is TRUE.

     */
    bool save(bool forceInsert = false,bool forceAllField = false) override;

    /// Insert the record, or update it in place if it conflicts on a key (upsert)
    /**
      A non-destructive alternative to save(): it runs
      "INSERT INTO ... ON CONFLICT(conflictColumns) DO UPDATE ...", so an
      existing row (identified by the conflict column(s)) is updated in place —
      keeping its primary key — instead of being replaced. Ideal for importing
      records from an API by a natural key on repeated fetches.

      @param conflictColumns The unique/primary column(s) identifying an existing
             row (e.g. a natural key from the source API).
      @param forceAllField TRUE to write all fields even if null.
      @return TRUE on success.

      @remarks Requires SQLite 3.24 or newer.
     */
    bool upsert(const QStringList &conflictColumns, bool forceAllField = false);

    /// Load the record that first match with filter
    bool load(QiWhere where);

    /// Remove the record from database
    /**
      @return TRUE if the record is successfully removed
     */
    [[nodiscard]] bool remove();

    /// Soft-delete: stamp the record's `deletedAt` column with the current time
    /// and save it, instead of DELETEing the row.
    /**
      Requires the model to declare a `deletedAt` field (QiField<QDateTime>).
      The row stays in the table; query live vs. trashed rows with qiAlive<T>()
      / qiTrashed<T>() (see qirelation.h). Returns false (with lastError set) if
      the model has no `deletedAt` field.
     */
    [[nodiscard]] bool softRemove();

    // --- Lifecycle hooks ---------------------------------------------------
    // Override these to run logic around persistence. clean() (above) is the
    // pre-save validation hook; these fire around successful operations.

    /// Called after a successful save()/upsert(). `created` is true for an insert.
    virtual void afterSave(bool created) { Q_UNUSED(created); }

    /// Called before remove(); return false to veto the deletion.
    virtual bool beforeRemove() { return true; }

    /// Called after a successful remove().
    virtual void afterRemove() {}

    /// Called after a successful load() populated this record.
    virtual void afterLoad() {}

    /// Model fields validation
    /**
        This method should be used to provide custom model validation, and to modify attributes on your model if desired.

        If the derived class do not implement their own clean function , it will always return TRUE (No error)

        A clean() override may call setError() to explain why validation failed;
        that message is then available from lastError().

        @see save
        @see setError
        @return TRUE if no error was found.
      */
    virtual bool clean();

    /// The error from the last save() / load() / remove() / upsert() on this record
    /**
      Returns a QiError describing why the last operation failed (or a
      "no error" QiError if it succeeded).

\code
    if (!user.save())
        qWarning() << user.lastError().text();
\endcode
     */
    QiError lastError() const;

    /// The list of initial data which should be inserted to database during table creation. Derived class should override the function to provide their custom record
    /**
      @see QiConnection::createTables
      @see QiListWriter
     */
    virtual QiSharedList initialData() const;

    /// Return a query object to retrieve record from this model
    /** The QI_MODEL macro will add an objects() function for the derived class.
      It will return a QiSharedQuery / QiQuery<T> object instance to query
      data from this data model.

      It provides a faster coding way for you to retrieve data:

      Example code:
\code
    qDebug() << User::objects().call("sum","karma").toInt(); // User is a QiModel.
\endcode
     */
    static QiSharedQuery objects();
    /// Return a query object to retrieve record from this model for specific database connection
    /**
        @param connecion The connection
        It is a overloaded function
     */
    static QiSharedQuery objects(QiConnection connection);

protected:
    /// Set the error for this record (call from a clean() override to explain a validation failure)
    void setError(const QiError &error);

    /// Set a validation error message (convenience for clean() overrides)
    void setError(const QString &message);

private:
    QiConnection m_connection;
    QiError m_error;
};

template<>
class QiModelMetaInfoHelper<QiModel>{
public:
    enum {Defined = 0 };
    /// Return the fields of QiModel
    static inline QList<QiModelMetaInfoField> fields() {
        QList<QiModelMetaInfoField> result;
        QiModel m;
        result << QiModelMetaInfoField("id",
                                       offsetof(QiModel,id),
                                       m.id.type(),
                                       m.id.clause()
                                       );
        return result;
    }
};

/// Declare a database field.
/**
  @param field The name of the field. You don't need to quote the string
  @param CLAUSE The column clause of the field. You may skip this parameter if not needed.
  @remarks This macro should be only used within QI_DECLARE_MODEL / QI_DECLARE_MODEL2

  It expands to a deferred (field, clause) tuple that QI_DECLARE_MODEL consumes
  twice: once to build the runtime metadata, and once to generate the typed
  Model::col() column descriptor. See qicolumns.h.

  @see QiClause
  @see QiNotNull
  @see QiUnique
  @see QiDefault
 */
#define QI_FIELD(field, ...) ( field , ##__VA_ARGS__ )

/// Declare a field with an explicit SQL column type, overriding the type Qivot
/// would infer from the C++ type.
/**
  @param field  The field name.
  @param sqltype A raw SQL type string (e.g. "REAL", "NUMERIC", "STRING"), or
         "" for a typeless column (no type between the name and its constraints).
  @param CLAUSE Optional column clauses (combine with `|`), as for QI_FIELD.

  \code
    QI_FIELD_AS(billed,    "REAL")                    // REAL instead of DOUBLE
    QI_FIELD_AS(closedUtc, "")                        // typeless column
    QI_FIELD_AS(ticketNo,  "STRING", QiNotNull)       // custom type + clause
  \endcode
 */
#define QI_FIELD_AS(field, sqltype, ...) \
    ( field , qiMergeSqlType(QiSqlType(sqltype) , ##__VA_ARGS__) )

/**
  See tests/modes/model1.h
 */
#define QI_DECLARE_MODEL_BEGIN(MODEL,NAME) \
        template<> \
        class QiModelMetaInfoHelper<MODEL> { \
        public: \
            typedef MODEL Table; \
            enum {Defined = 1 }; \
            static inline QString className() { \
                return #MODEL; \
            } \
            static inline QList<QiModelMetaInfoField> fields() {\
                QList<QiModelMetaInfoField> result;\
                MODEL m;

#define QI_DECLARE_MODEL_END(MODEL,NAME) \
                return result; \
            } \
        }; \
        inline QString MODEL::tableName() const { \
            return NAME; \
        } \
        inline QString MODEL::TableName() { \
            return NAME; \
        } \
        inline QiModelMetaInfo *MODEL::metaInfo() const { \
            static QiModelMetaInfo *meta = 0; \
            if (!meta){ \
                meta = qiMetaInfo<MODEL>(); \
            } \
            return meta; \
        } \
        inline auto MODEL::objects() { \
            return QiQuery<MODEL>(); \
        } \
        inline auto MODEL::objects(QiConnection connection) { \
            return QiQuery<MODEL>(connection); \
        } \
        inline QDebug operator<< (QDebug d, const MODEL& model) { \
            d.nospace() << &model; \
            return d.space(); \
        }

/// Declare a model
/**
  For example,

\code


/// User account database
class User : public QiModel {
    QI_MODEL
public:
    QiField<QString> userId;
    QiField<QDateTime> creationDate;
    QiField<qreal> karma;
};

/// Declare the model and the field clause
QI_DECLARE_MODEL(User,
                 "user", // the table name.
                 QI_FIELD(userId , QiNotNull | QiUnique),
                 QI_FIELD(creationDate , QiDefault("CURRENT_TIMESTAMP") ),
                 QI_FIELD(karma)
                 );

\endcode

@see QI_MODEL
@see QI_FIELD
 */
#define QI_DECLARE_MODEL(MODEL,NAME,...) \
        QI_DECLARE_MODEL_BEGIN(MODEL,NAME) \
            result << QiModelMetaInfoHelper<QiModel>::fields(); \
            QiModelMetaInfoField* list[] = { QI_COL_FOR_EACH(QI_COL_EMIT_META, __VA_ARGS__) 0 }; \
            result << _qiMetaInfoCreateFields(list) ; \
        QI_DECLARE_MODEL_END(MODEL,NAME) \
        QI_GEN_COLUMNS(MODEL, __VA_ARGS__)

/// Declare a model that has NO built-in auto-increment `id` column.
/**
  Identical to QI_DECLARE_MODEL, except the hidden
  `id INTEGER PRIMARY KEY AUTOINCREMENT` column is omitted. Mark one of your own
  fields as the primary key with QiPrimary — typically a meaningful string id:

\code
    class Contact : public QiModel {
        QI_MODEL
    public:
        QiField<QString> contactId;
        QiField<QString> name;
    };
    QI_DECLARE_MODEL_NOID(Contact, "contact",
                          QI_FIELD(contactId, QiPrimary | QiNotNull),
                          QI_FIELD(name));
\endcode

  save()/load()/remove() and queries all work off the declared primary key.
  Note: there is no `id` column — `Model::col()` has no `.id`, and such a model
  cannot be an FTS content_rowid table. (Foreign keys reference its declared
  primary key instead of `id`.)

  @see QiPrimary
 */
#define QI_DECLARE_MODEL_NOID(MODEL,NAME,...) \
        QI_DECLARE_MODEL_BEGIN(MODEL,NAME) \
            QiModelMetaInfoField* list[] = { QI_COL_FOR_EACH(QI_COL_EMIT_META, __VA_ARGS__) 0 }; \
            result << _qiMetaInfoCreateFields(list) ; \
        QI_DECLARE_MODEL_END(MODEL,NAME) \
        QI_GEN_COLUMNS_NOID(MODEL, __VA_ARGS__)

/// Declare a model which is not a direct sub-class of QiModel
#define QI_DECLARE_MODEL2(MODEL,NAME,PARENT,...) \
        QI_DECLARE_MODEL_BEGIN(MODEL,NAME) \
            result << QiModelMetaInfoHelper<PARENT>::fields(); \
            QiModelMetaInfoField* list[] = { QI_COL_FOR_EACH(QI_COL_EMIT_META, __VA_ARGS__) 0 }; \
            result << _qiMetaInfoCreateFields(list) ; \
        QI_DECLARE_MODEL_END(MODEL,NAME) \
        QI_GEN_COLUMNS(MODEL, __VA_ARGS__)

/// The QI_MODEL macro must appear in the class definition that declares model's virtual function for database access
/** \def QI_MODEL

  For example,

\code


/// User account database
class User : public QiModel {
    QI_MODEL
public:
    QiField<QString> userId;
    QiField<QDateTime> creationDate;
    QiField<qreal> karma;
};

/// Declare the model and the field clause
QI_DECLARE_MODEL(User,
                 "user", // the table name.
                 QI_FIELD(userId , QiNotNull | QiUnique),
                 QI_FIELD(creationDate , QiDefault("CURRENT_TIMESTAMP") ),
                 QI_FIELD(karma)
                 );

\endcode

@see QI_DECLARE_MODEL
 */
#define QI_MODEL \
public: \
    enum { QiModelDefined = 1 }; \
    virtual inline QString tableName() const ; \
    static inline QString TableName(); \
    virtual inline QiModelMetaInfo *metaInfo() const; \
    static inline auto objects(); \
    static inline auto objects(QiConnection connection); \
    struct Columns; \
    static Columns col(); \
    template <class T> friend class QiModelMetaInfoHelper;\

/// Print model field for debugging
inline QDebug operator<< (QDebug d, const QiModel* model){
    QiModelMetaInfo *metaInfo = model->metaInfo();
    QStringList fields = metaInfo->fieldNameList();
    QStringList col;
    foreach (QString field,fields){
        QVariant value = metaInfo->value(model,field);
        if (value.isNull())
            continue;
        col << QString("%1=%2").arg(field).arg(value.toString());
    }

    QString res = QString("%1[%2]")
                  .arg(metaInfo->className())
                  .arg(col.join(","));

    d.nospace() << res;

    return d.space();
}

#endif // QiMODEL_H

// ---- src/qigadget.h ----------------------------------------------
#ifndef QiGADGET_H
#define QiGADGET_H

#include <QMetaType>

/// Helper for exposing a QiModel to Qt's meta-object system (MOC) and QML.
/**
  A normal Qivot model (QI_MODEL + QiField) is deliberately *not* a QObject and
  is invisible to Qt's meta-object system. To expose a model to QML, make it a
  Q_GADGET and declare each field as a Q_PROPERTY.

  Write **`Q_GADGET`** (literally — qmake's automoc scans the source text for the
  keyword, so it must not be hidden behind a macro) followed by `QI_MODEL`, then
  use `QI_QML_FIELD` in place of each bare `QiField` member. The model must live
  in a header listed in your project's `HEADERS` so moc processes it.

\code
    class Post : public QiModel {
        Q_GADGET
        QI_MODEL
        QI_QML_FIELD(int,     remoteId)
        QI_QML_FIELD(QString, title)
    };
    QI_DECLARE_MODEL(Post, "post",
                     QI_FIELD(remoteId, QiUnique | QiNotNull),
                     QI_FIELD(title));
\endcode

  The result is a value type whose properties QML can read and write
  (`post.title`). Qivot's own save() / load() / query API keeps working
  unchanged — the gadget adds no per-instance state. For exposing a *list* of
  records to a QML view, see QiListModel.
 */

/// Declare a database field AND expose it to QML as a Q_PROPERTY
/**
  @param TYPE The field's value type (QString, int, double, QDateTime, ...).
  @param NAME The field name.

  Expands to a `QiField<TYPE> NAME;` member plus a Q_PROPERTY with read/write
  accessors that bridge the field's QVariant storage. Requires a literal
  `Q_GADGET` in the class so that moc processes the header.
 */
#define QI_QML_FIELD(TYPE, NAME) \
    Q_PROPERTY(TYPE NAME READ _qiGet_##NAME WRITE _qiSet_##NAME) \
public: \
    QiField<TYPE> NAME; \
    TYPE _qiGet_##NAME() const { return NAME; } \
    void _qiSet_##NAME(const TYPE &value) { NAME.set(QVariant::fromValue(value)); }

#endif // QiGADGET_H

// ---- src/qijsonmapper.h ------------------------------------------
#ifndef QiJSONMAPPER_H
#define QiJSONMAPPER_H

#include <QJsonObject>
#include <QJsonArray>
#include <QJsonValue>
#include <QJsonDocument>
#include <QByteArray>

/// Maps between JSON (QJsonObject / QJsonArray) and DQuest models
/**
  QiJsonMapper converts JSON documents into QiModel instances and back. Only the
  fields declared on the model are considered — any extra keys in the JSON are
  ignored, and any model field missing from the JSON is left untouched. Values
  are coerced to each field's declared type (so an ISO-8601 string maps into a
  QiField\<QDateTime\>, a JSON number into a QiField\<int\>, and so on).

  This class is pure QtCore — it performs no I/O and no threading. For loading
  JSON from an HTTP endpoint on a worker thread, see QiJsonRequest.

\code
    QJsonArray array = QJsonDocument::fromJson(bytes).array();
    QiList<Post> posts = QiJsonMapper::map<Post>(array);
\endcode
 */
class QiJsonMapper {
public:
    /// Populate an existing model from a JSON object
    /**
      @param model  The model to populate (its fields are matched by name).
      @param object The source JSON object.
      @return TRUE if at least one field was assigned.
     */
    static bool fromJson(QiAbstractModel *model, const QJsonObject &object);

    /// Create and populate a model of the given meta type from a JSON object
    /**
      @return A newly allocated model. Ownership is passed to the caller.
     */
    static QiAbstractModel *fromJson(QiModelMetaInfo *metaInfo, const QJsonObject &object);

    /// Map a JSON array of objects into a QiSharedList of the given meta type
    /**
      Non-object array elements are skipped. The returned list owns the models.
     */
    static QiSharedList fromJson(QiModelMetaInfo *metaInfo, const QJsonArray &array);

    /// Serialize a model to a JSON object (one member per declared field)
    static QJsonObject toJson(const QiAbstractModel *model);

    /// Typed convenience: map a JSON array into a QiList\<T\>
    template <typename T>
    static QiList<T> map(const QJsonArray &array) {
        return QiList<T>( fromJson(qiMetaInfo<T>(), array) );
    }

    /// Typed convenience: map a JSON object into a T
    template <typename T>
    static T map(const QJsonObject &object) {
        T model;
        fromJson(&model, object);
        return model;
    }

    /// Coerce a JSON value to a QVariant of the field's declared QMetaType id
    static QVariant jsonToVariant(const QJsonValue &value, int targetType);

    // --- pure JSON <-> object (raw bytes/string, no database involved) -------

    /// Deserialize a JSON *object* document into a model of type T.
    /**
      Pure in-memory: parses the bytes and populates a T. Nothing is persisted.
\code
    User u = QiJsonMapper::deserialize<User>(bytes);   // JSON text -> object
\endcode
     */
    template <typename T>
    static T deserialize(const QByteArray &json) {
        return map<T>(QJsonDocument::fromJson(json).object());
    }

    /// Deserialize a JSON *array* document into a QiList<T>.
    template <typename T>
    static QiList<T> deserializeList(const QByteArray &json) {
        return map<T>(QJsonDocument::fromJson(json).array());
    }

    /// Serialize a model to a JSON object document (raw bytes).
    /**
\code
    QByteArray bytes = QiJsonMapper::serialize(&user);   // object -> JSON text
\endcode
     */
    static QByteArray serialize(const QiAbstractModel *model,
                                QJsonDocument::JsonFormat format = QJsonDocument::Indented);

    /// Serialize a list of models to a JSON array document (raw bytes).
    static QByteArray serialize(const QiSharedList &list,
                                QJsonDocument::JsonFormat format = QJsonDocument::Indented);
};

#endif // QiJSONMAPPER_H

// ---- src/qikeyset.h ----------------------------------------------
#ifndef QiKEYSET_H
#define QiKEYSET_H

#include <QString>
#include <QVariant>

/// Keyset (a.k.a. cursor / "seek") pagination.
/**
  Pages through an ordered result by remembering the last row's key and asking
  for rows *after* it — `WHERE key > :cursor ORDER BY key LIMIT n` — instead of
  `LIMIT n OFFSET n*page`. Each page is a single index seek, so it stays fast no
  matter how deep you scroll; `OFFSET` re-scans every skipped row and gets slower
  the further you go.

  The key column must be unique and match the sort order — typically the primary
  key. Pass an optional base filter to page through a subset.

\code
    QiKeyset<Event> pager("id", 100);          // key column, page size
    while (!pager.atEnd()) {
        QiList<Event> page = pager.next();
        for (int i = 0; i < page.size(); i++) { ... }
    }

    // Save pager.cursor() and later resume exactly where you left off:
    pager.seek(savedCursor);
\endcode
 */
template <typename T>
class QiKeyset {
public:
    /// @param keyField    unique column to seek on (e.g. "id")
    /// @param pageSize    rows per page
    /// @param ascending   sort/seek direction
    /// @param baseFilter  optional condition ANDed into every page
    explicit QiKeyset(const QString &keyField, int pageSize = 50,
                      bool ascending = true, QiWhere baseFilter = QiWhere())
        : m_key(keyField), m_size(pageSize > 0 ? pageSize : 50),
          m_asc(ascending), m_base(baseFilter) {}

    /// Fetch the next page (empty once exhausted).
    QiList<T> next() {
        if (m_atEnd)
            return QiList<T>();

        QiWhere cond = m_base;
        if (m_hasCursor) {
            QiWhere seek = m_asc ? (QiWhere(m_key) > m_cursor)
                                 : (QiWhere(m_key) < m_cursor);
            cond = m_base.isNull() ? seek : (m_base && seek);
        }

        QiQuery<T> q;
        if (!cond.isNull())
            q = q.filter(cond);
        q = q.orderBy(m_key + (m_asc ? QStringLiteral(" asc") : QStringLiteral(" desc")))
             .limit(m_size);

        QiList<T> page = q.all();
        if (page.size() < m_size)
            m_atEnd = true;
        if (page.size() > 0) {
            QiModelMetaInfo *info = qiMetaInfo<T>();
            m_cursor = info->value(page.at(page.size() - 1), m_key);
            m_hasCursor = true;
        }
        return page;
    }

    /// True once a short/empty page proved there's nothing more.
    bool atEnd() const { return m_atEnd; }

    /// The last key seen — a compact, stable cursor you can persist and resume.
    QVariant cursor() const { return m_cursor; }

    /// Resume paging from a saved cursor (the next page starts after `key`).
    void seek(const QVariant &key) { m_cursor = key; m_hasCursor = true; m_atEnd = false; }

    /// Start over from the beginning.
    void reset() { m_cursor = QVariant(); m_hasCursor = false; m_atEnd = false; }

private:
    QString  m_key;
    int      m_size;
    bool     m_asc;
    QiWhere  m_base;
    QVariant m_cursor;
    bool     m_hasCursor = false;
    bool     m_atEnd = false;
};

#endif // QiKEYSET_H

// ---- src/qistream.h ----------------------------------------------
/**
    @author Ben Lau
 */

#ifndef QiSTREAM_H
#define QiSTREAM_H


/// QiStream class provides a stream interface for reading and writing data model field
/**

    Using QiStrem's streaming operator , you could read and write the
    data model field in a simplifer way.

    Assume you have the following data model:

\code

/// An example model for people's height and weight data
class HealthCheck : public QiModel {
    QI_MODEL
public:

    QiField<QString> name;
    QiField<int>     height;
    QiField<double>  weight;
};

QI_DECLARE_MODEL(HealthCheck,
                 "healthcheck",
                 QI_FIELD(name , QiNotNull),
                 QI_FIELD(height),
                 QI_FIELD(weight)
                 );
\endcode

    You can read and write using the streaming operators

    Write example:
\code
    HealthCheck record;
    QiStream stream(&record);

    stream << "Tester 1" << 179 << 120.5;
    //Then record = ["Tester 1" , 179,120.5]
\endcode

    Read example:

\code
    QiStream stream(&record);
    QString name;
    QString height;
    QString weight;

    stream >> name >> height >> weight;
\endcode

    @remarks The sequence of read/write is equal to the registration order in QI_DECLARE_MODEL. It is nothing related to its declaration order in class declaration.
 */
class QiStream
{
public:
    /// Default constructor
    QiStream();

    /// Construct a QiStream operates on target model
    /**
      The constructor will open the target model for read/write automatically
      @see open
     */
    QiStream(QiAbstractModel* model);

    /// Open and set the target model for read / write
    /**
      @param model The target model for read / write. The model must contains more than a field. Otherwise the operation will be failed.
      @remarks It will reset the value returned by currentField()
     */
    void open(QiAbstractModel* model);

    /// Get the target model
    QiAbstractModel* model();

    /// Get the index of the current reading/ writing field
    int currentField();

    /// Write the value to data model at current field
    /**
      @remarks The "id" field is ignored in writing
     */
    void write(const QVariant value);

    /// Read the current field and save to target variable
    void read(QVariant &target);

    /// Close the stream and release the resource holding
    void close();

    /// Write the value to data model at current field
    /**
      @remarks It is a wrapper of write().
     */
    QiStream& operator<< (const QVariant value);

    /// Read the current field and save to target variable
    /**
      @remarks It is a wrapper of read().
     */
    QiStream& operator>> (QVariant &target);

    /// Read the current field and save to target variable
    /**
      @remarks It is a wrapper of read().
     */
    QiStream& operator>> (QString& target);

    /// Read the current field and save to target variable
    /**
      @remarks It is a wrapper of read().
     */
    QiStream& operator>> (int& target);

    /// Read the current field and save to target variable
    /**
      @remarks It is a wrapper of read().
     */
    QiStream& operator>> (double& target);

    /// Read the current field and save to target variable
    /**
      @remarks It is a wrapper of read().
     */
    QiStream& operator>> (QDateTime& target);

private:
    QiAbstractModel* m_model;

    /// The current read/write field
    int m_current;
};

#endif // QiSTREAM_H

// ---- src/qilistwriter.h ------------------------------------------
/**
    @author Ben Lau
 */

#ifndef QiLISTWRITER_H
#define QiLISTWRITER_H


/// QiListWriter is a utility class to create the content on QiList object
/**

  QiListWriter provides a stream interface for writing data to target QiList.

  In the first time you call append() or << operator , QiListWriter inserts a new
  model instance to the target list automatically.

  Then it bind a QiStream object with the model instance, the input from append()
  or << operator is redirected to the model instance through the QiStream
  interface. The stream will be closed when all of the field is written already.

  The next time you call append() or << operator will inserts a new model instance
  and repeat the above process.

  For example:

  Assume you have the following data model:

\code

/// An example model for people's height and weight data
class HealthCheck : public QiModel {
    QI_MODEL
public:

    QiField<QString> name;
    QiField<int>     height;
    QiField<double>  weight;
};

QI_DECLARE_MODEL(HealthCheck,
                 "healthcheck",
                 QI_FIELD(name , QiNotNull),
                 QI_FIELD(height),
                 QI_FIELD(weight)
                 );
\endcode

  You may create the content on QiList by :

\code

    QiList<HealthCheck> list;
    QiListWriter writer(&list);

    writer << "Tester 1" << 179 << 120.5; // list.size() == 1

    writer << "Tester 2" << 160 << 80
           << "Tester 3" << 120 << 60; // list.size() == 3

\endcode

  Sometimes you may not want to set all of the field on the model instance.
  Only the first n-th column are interested. Then you may
  append the result of next() to the stream, the stream will be closed immediately.
  The next append() or trigger will trigger the insertion of new model instance.

Example:

\code
    QiList<HealthCheck> list;
    QiListWriter writer(&list);

    writer << "Tester 1" << 179 << QiListWriter::next()  // weight field is ignored.
           << "Tester 2" << 160 << writer.next() // An alternative to call next().
           << "Tester 3" << 120;  // list.size() == 3

\endcode
  @see QiStream

 */

class QiListWriter
{
public:
    /// Construct a QiListWriter object. Before you can use it for reading or writing , you should call open() to assign a target list.
    QiListWriter();

    /// Construct a QiListwriter operates on target list
    /** This constructor will construct the QiListWriter object and open the target list for reading or writing.
      @see open
     */
    QiListWriter(QiSharedList *list);

    /// Construct a QiListWriter operates on target list with specific database connection
    /**
      This constructor will construct the QiListWriter object and open the target list for reading or writing.
      Moreover, it will set the default database connection for newly created model.

      @see open
      @see setConnection
     */
    QiListWriter(QiSharedList *list,QiConnection connection);

    /// Open and set the target list for writing
    /**
      @param list The target list for writing. The list must be binded with a data model(It's metaInfo() should be non-null)
     */
    bool open(QiSharedList *list);

    /// Get the target list for writing
    QiSharedList *list();

    /// Append a value to data model field
    void append(QVariant value);

    /// Close the writer
    void close();

    /// Append a value to data model field
    /**
      @remarks It is a wrapper of append().
     */
    QiListWriter& operator<< (const QVariant value);

    /// A symbol for stream termination
    /**
      @see next();
     */
    class Next {
    };

    /// Return a symbol to close the stream to current input model.
    /**
      If the result of this function is passed to append() or << operator,
      then the stream is closed immediately. The next call to append() or <<
      operator will insert a new model instance instead of write to
      the orignal writing model.

Example model:

\code
class HealthCheck : public QiModel {
    QI_MODEL
public:

    QiField<QString> name;
    QiField<int>     height;
    QiField<double>  weight;
};

QI_DECLARE_MODEL(HealthCheck,
                 "healthcheck",
                 QI_FIELD(name , QiNotNull),
                 QI_FIELD(height),
                 QI_FIELD(weight)
                 );
\endcode

Example code:
\code
    QiList<HealthCheck> list;
    QiListWriter writer(&list);

    writer << "Tester 1" << 179 << QiListWriter::next()  // weight field is ignored.
           << "Tester 2" << 160 << writer.next() // An alternative to call next().
           << "Tester 3" << 120;  // list.size == 3

\endcode

     */
    static QVariant next();

    /// Set the database connection for newly created model
    /** QiListWriter create new model on the target QiList
      when user append content. It will initialize model's
      connection according to the value set in this function.

      Usually you don't need to use this function unless you
      have multiple database connection in the application.
     */
    void setConnection(QiConnection value);

    /// Get the database connection set for newly created model
    QiConnection connection();

private:

    /// The target list for writing
    QiSharedList *m_list;

    /// The stream for writing to target list
    QiStream m_stream;

    /// The connection set for newly created model instance
    QiConnection m_connection;
};

Q_DECLARE_METATYPE(QiListWriter::Next);

#endif // QiLISTWRITER_H

// ---- src/qilog.h -------------------------------------------------
#ifndef QiLOG_H
#define QiLOG_H

#include <QString>
#include <QDebug>
#include <functional>

class QSqlQuery;

/// Qivot's debug logger — timestamped, filterable, colorized.
/**
  Logging is **off by default** (zero overhead). Turn it on when you want to see
  what Qivot is doing against the database:

\code
    QiLog::enableAll();                       // everything, at Debug level
    // or fine-grained:
    QiLog::setEnabled(true);
    QiLog::setLevel(QiLog::Debug);
    QiLog::setCategories(QiLog::Sql | QiLog::Connection);   // only these
\endcode

  Each line carries a timestamp, a category tag and a level, e.g.

\verbatim
    [2026-07-21 01:37:12.345] [SQL ] DEBUG  SELECT ALL user.* FROM user WHERE karma > :arg0  | args: [:arg0=50] | rows: 3 | 0.42ms
    [2026-07-21 01:37:12.361] [SQL ] ERROR  INSERT INTO user (...) ...  | error: UNIQUE constraint failed: user.userId
\endcode

  Redirect anywhere (a file, your app's logger, a test buffer) with setHandler().
  You can also log your own lines in the same format via qiLog() / QiLog::debug().
 */
class QiLog {
public:
    /// Severity, low to high. A message is shown only if its level >= the
    /// configured threshold (see setLevel()).
    enum Level { Trace, Debug, Info, Warning, Error };

    /// Message categories (a bitmask — enable any subset with setCategories()).
    enum Category {
        General    = 1 << 0,   ///< your own messages / uncategorised
        Connection = 1 << 1,   ///< open / close
        Sql        = 1 << 2,   ///< every statement executed, with params + timing
        Model      = 1 << 3,   ///< model-level events (validation failures, ...)
        Json       = 1 << 4    ///< JSON mapping
    };
    enum { AllCategories = General | Connection | Sql | Model | Json };

    // ---- configuration ----------------------------------------------------
    static void  setEnabled(bool on);
    static bool  isEnabled();
    static void  setLevel(Level level);        ///< threshold (default Debug)
    static Level level();
    static void  setCategories(int mask);      ///< default: AllCategories
    static int   categories();
    static void  setTimestamps(bool on);       ///< default: true
    static void  setColorized(bool on);        ///< default: true (built-in sink)

    /// One-liner: enable logging for all categories at a level (default Debug).
    static void  enableAll(Level level = Debug);

    /// Custom sink: receives (level, category, formatted-line-without-color).
    /// Pass nullptr to restore the built-in stderr sink.
    using Handler = std::function<void(Level, int, const QString &)>;
    static void  setHandler(Handler handler);

    // ---- cheap predicate (guard expensive message building) ---------------
    static bool  wants(int category, Level level);

    // ---- emit -------------------------------------------------------------
    static void  write(int category, Level level, const QString &message);
    static void  trace  (const QString &m, int c = General) { write(c, Trace,   m); }
    static void  debug  (const QString &m, int c = General) { write(c, Debug,   m); }
    static void  info   (const QString &m, int c = General) { write(c, Info,    m); }
    static void  warning(const QString &m, int c = General) { write(c, Warning, m); }
    static void  error  (const QString &m, int c = General) { write(c, Error,   m); }

    // ---- used by the ORM internals (safe to ignore) -----------------------
    /// Log a just-executed query: SQL text, bound params, row count, error and
    /// (if provided) elapsed time. Level is Error when the query failed.
    static void  logQuery(const QSqlQuery &query, qint64 elapsedNs = -1);
};

/// QDebug-style stream for your own log lines, flushed when it goes out of scope:
/// `qiLog(QiLog::General, QiLog::Info) << "loaded" << n << "rows";`
class QiLogStream {
public:
    QiLogStream(int category, QiLog::Level level)
        : m_cat(category), m_level(level), m_on(QiLog::wants(category, level)) {}
    ~QiLogStream() { if (m_on) QiLog::write(m_cat, m_level, m_buf.trimmed()); }

    template <typename T>
    QiLogStream &operator<<(const T &value) {
        if (m_on) QDebug(&m_buf).noquote() << value;
        return *this;
    }
private:
    int          m_cat;
    QiLog::Level m_level;
    bool         m_on;
    QString      m_buf;
};

/// Convenience factory: `qiLog(QiLog::Sql, QiLog::Debug) << ...;`
inline QiLogStream qiLog(int category = QiLog::General,
                         QiLog::Level level = QiLog::Debug) {
    return QiLogStream(category, level);
}

#endif // QiLOG_H

// ---- src/qimigrator.h --------------------------------------------
#ifndef QiMIGRATOR_H
#define QiMIGRATOR_H

#include <QVector>
#include <QString>
#include <functional>

/// Versioned schema migrations, tracked by SQLite's `PRAGMA user_version`.
/**
  Register migrations keyed by an increasing version number, then call
  migrate(): every migration whose version is greater than the database's
  current `user_version` runs in order, each inside its own transaction, and
  `user_version` is advanced to match. Re-running is a no-op — already-applied
  migrations are skipped — so migrate() is safe to call on every startup.

  Each step is a callable `bool(QiConnection&)`; return false (or let a Qivot
  call fail) to abort — the step's transaction is rolled back and the version is
  left unchanged.

\code
    QiMigrator m(conn);
    m.add(1, "create tables", [](QiConnection &c){
        return c.query().exec("CREATE TABLE note (id INTEGER PRIMARY KEY, title TEXT)");
    });
    m.add(2, "add body", [](QiConnection &c){
        return c.query().exec("ALTER TABLE note ADD COLUMN body TEXT");
    });

    int applied = m.migrate();          // -> number of migrations run this time
    if (applied < 0) qWarning() << m.lastError();
\endcode
 */
class QiMigrator {
public:
    /// A single migration: mutate the schema, return true on success.
    using Step = std::function<bool(QiConnection &)>;

    explicit QiMigrator(QiConnection connection = QiConnection::defaultConnection());

    /// Register a migration to `version` (must be > 0). add() order is irrelevant;
    /// migrations always run in ascending version order.
    void add(int version, const QString &name, Step step);

    /// The database's current schema version (`PRAGMA user_version`; 0 if fresh).
    int currentVersion() const;

    /// The highest registered migration version.
    int targetVersion() const;

    /// Run every pending migration in order.
    /**
      @return the number of migrations applied this call (0 if already
              up to date), or -1 on failure (see lastError()).
     */
    int migrate();

    /// Human-readable reason migrate() returned -1 (empty on success).
    QString lastError() const;

private:
    struct Entry { int version; QString name; Step step; };
    void setUserVersion(int version);

    mutable QiConnection m_conn;   // query() is non-const; currentVersion() is logically const
    QVector<Entry> m_steps;
    QString        m_error;
};

#endif // QiMIGRATOR_H

